 90→    @Override
 91→    public BatchMigrationTaskVo getBatchMigrationTaskInfo(String batchId) {
 92→        List<SpaceNodeMigrationTaskEntity> tasks = spaceNodeMigrationTaskService.listByBatchId(batchId);
 93→        if (tasks.isEmpty()) {
 94→            return BatchMigrationTaskVo.builder().batchId(batchId).tasks(List.of()).build();
 95→        }
 96→
 97→        // 批量查询空间站名称，避免 N+1
 98→        Set<String> spaceIds = tasks.stream().map(SpaceNodeMigrationTaskEntity::getSourceSpaceId).collect(Collectors.toSet());
 99→        Map<String, String> spaceNameMap = new HashMap<>();
100→        for (String spaceId : spaceIds) {
101→            try {
102→                com.yottastudios.ns.collabspace.space.entity.SpaceEntity space = spaceService.getBySpaceId(spaceId);
103→                if (space != null) {
104→                    spaceNameMap.put(spaceId, space.getName());
105→                }
106→            } catch (Exception e) {
107→                log.warn("Failed to get space name for spaceId={}, error={}", spaceId, e.getMessage());
108→            }
109→        }
110→
111→        List<BatchMigrationSubTaskVo> subTasks = tasks.stream().map(task -> {
112→            String spaceName = spaceNameMap.getOrDefault(task.getSourceSpaceId(), "");
113→            return new BatchMigrationSubTaskVo(task, spaceName);
114→        }).toList();
115→
116→        return BatchMigrationTaskVo.builder().batchId(batchId).tasks(subTasks).build();
117→    }
