138→    @Override
139→    public List<VersionSnapshotVo> listVersionSnapshot(Long spaceNodeId, Integer status) {
140→        List<CollabspaceVersionSnapshotEntity> list = versionSnapshotService.getByNodeId(spaceNodeId, status);
141→        if (list.isEmpty()){
142→            return new ArrayList<>();
143→        }
144→        List<Long> creatorList = new ArrayList<>(list.stream().map(CollabspaceVersionSnapshotEntity::getCreatedBy).toList());
145→        List<Long> operatorList = list.stream().map(CollabspaceVersionSnapshotEntity::getOperatorId).toList();
146→        if (!operatorList.isEmpty()){
147→            creatorList.addAll(operatorList);
148→        }
149→        creatorList = creatorList.stream().filter(o -> o != null && o != 0L).toList();
150→        List<UserSimpleInfoVo> userList = apitableGrpcClientService.getUserByIds(creatorList);
151→        List<VersionSnapshotVo> voList = new ArrayList<>();
152→        list.forEach(item -> {
153→            Long userId = item.getOperatorId();
154→            UserSimpleInfoVo operator = userList.stream().filter(o -> Objects.equals(o.getId(), userId)).findFirst().orElse(null);
155→            UserSimpleInfoVo creator = userList.stream().filter(o -> Objects.equals(o.getId(), item.getCreatedBy())).findFirst().orElse(null);
156→            String opUserName = operator == null ? "" : operator.getNickName();
157→            String createUserName = creator == null ? "" : creator.getNickName();
158→            String deleteTime = status.equals(VersionSnapshotStatusEnum.DISABLED.getValue()) ?
159→                    item.getUpdatedAt().toString() : "";
160→            voList.add(VersionSnapshotVo.builder().snapshotName(item.getSnapshotName()).id(item.getId().toString())
161→                    .snapshotId(item.getSnapshotId()).snapshotCreator(createUserName).
162→                    snapshotDeleteUser(opUserName).snapshotCreateTime(item.getCreatedAt().toString()).
163→                    snapshotDeleteTime(deleteTime).build());
164→        });
165→        List<VersionSnapshotVo> finalList = voList;
166→        finalList = finalList.stream().sorted(Comparator.comparing(VersionSnapshotVo::getSnapshotCreateTime)).toList();
167→        return finalList;
168→    }
