175→    @Override
176→    public List<FolderPathItem> getNodeFolderPath(Long spaceNodeId) {
177→        // 1. 通过 relId 获取从当前节点到根的所有祖先节点（含自身）
178→        List<NodeEntity> ancestors = nodeService.listAncestorsByRelId(spaceNodeId);
179→        if (ancestors.isEmpty()) {
180→            return List.of();
181→        }
182→
183→        // 2. 构建 id -> NodeEntity 映射，找到当前节点
184→        Map<Long, NodeEntity> idToNode = new HashMap<>();
185→        NodeEntity current = null;
186→        for (NodeEntity n : ancestors) {
187→            if (n == null || n.getId() == null) continue;
188→            idToNode.put(n.getId(), n);
189→            if (Objects.equals(n.getRelId(), spaceNodeId)) {
190→                current = n;
191→            }
192→        }
193→        if (current == null) {
194→            return List.of();
195→        }
196→
197→        // 3. 从当前节点向上遍历，收集所有父节点的 relId（不含自身）
198→        List<Long> parentRelIds = new ArrayList<>();
199→        Set<Long> visited = new HashSet<>();
200→        NodeEntity node = idToNode.get(current.getParentId());
201→        while (node != null && node.getRelId() != null && !visited.contains(node.getId())) {
202→            visited.add(node.getId());
203→            parentRelIds.add(node.getRelId());
204→            node = idToNode.get(node.getParentId());
205→        }
206→
207→        if (parentRelIds.isEmpty()) {
208→            return List.of();
209→        }
210→
211→        // 4. 批量查询 SpaceNode 获取名称和类型
212→        List<SpaceNodeEntity> spaceNodes = spaceNodeService.listByIds(parentRelIds);
213→        Map<Long, SpaceNodeEntity> spaceNodeMap = new HashMap<>();
214→        for (SpaceNodeEntity sn : spaceNodes) {
215→            spaceNodeMap.put(sn.getId(), sn);
216→        }
217→
218→        // 5. 反转顺序（从根到叶），只保留文件夹类型
219→        Collections.reverse(parentRelIds);
220→        List<FolderPathItem> result = new ArrayList<>();
221→        for (Long relId : parentRelIds) {
222→            SpaceNodeEntity sn = spaceNodeMap.get(relId);
223→            if (sn != null && Objects.equals(sn.getType(), SpaceNodeTypeEnum.FOLDER.getValue())) {
224→                result.add(FolderPathItem.builder()
225→                        .id(sn.getId())
226→                        .name(sn.getName())
227→                        .build());
228→            }
229→        }
230→        return result;
231→    }
